$output = "C:\Users\Public\api_keys_found.json"
$results = @{}
$keywords = @('api_key', 'apikey', 'API_KEY', 'sk-', 'sk-ant-', 'OPENAI_API_KEY', 
              'ANTHROPIC_API_KEY', 'bearer', 'token', 'secret', 'runway', 'kling', 
              'luma', 'gemini', 'elevenlabs', 'stability', 'recraft', 'ideogram',
              'minimax', 'vidu', 'meshy', 'rodin', 'tripo')

$searchPaths = @(
    "C:\ComfyUI\user",
    "C:\ComfyUI\custom_nodes",
    "C:\ComfyUI\input",
    "$env:USERPROFILE\.comfyui",
    "$env:APPDATA\ComfyUI"
)

foreach ($searchPath in $searchPaths) {
    if (Test-Path $searchPath) {
        Get-ChildItem -Path $searchPath -Recurse -Include *.json,*.yaml,*.yml,*.env,*.cfg,*.py,*.txt -ErrorAction SilentlyContinue | ForEach-Object {
            $content = Get-Content $_.FullName -Raw -ErrorAction SilentlyContinue
            foreach ($kw in $keywords) {
                if ($content -match $kw) {
                    $results[$_.FullName] = $content.Substring(0, [Math]::Min(2000, $content.Length))
                    break
                }
            }
        }
    }
}

$results | ConvertTo-Json -Depth 3 | Out-File -FilePath $output -Encoding UTF8
"API_KEY_SEARCH_COMPLETE" | Out-File -FilePath "C:\Users\Public\search_complete.txt"
